/**************************************************************************************

   Загрузка новых сообщений из избранного

**************************************************************************************/
CREATE PROCEDURE FeedFavoriteLoadNew
  @ChangeDateHash nvarchar(16),
  @Recipient bigint,
  @MaxCount bigint,
  @AllMessages bit
AS
BEGIN

  set @ChangeDateHash = isnull(@ChangeDateHash, '');

  select top (@MaxCount)
      Id, Recipient, ActionObjectId, ActionObjectUid, ChangeDateHash, IsDelete
  from FeedFavorite
  where
      Recipient = @Recipient
      and (IsDelete = 0 or @AllMessages = 1)
      and ChangeDateHash > @ChangeDateHash
  order by ChangeDateHash

END


/**************************************************************************************

   Загружает указанное родительское сообщение без комментариев.

**************************************************************************************/
CREATE PROCEDURE FeedParentMessageLoad
    @p_Recipient bigint,
    @p_ParentObjectUid uniqueidentifier,
    @p_ParentObjectId bigint
AS
BEGIN

    declare @Id bigint,
      @Subject nvarchar(max),
      @Text nvarchar(max),
      @ActionObjectUid uniqueidentifier,
      @ActionUid uniqueidentifier,
      @ActionObjectId bigint,
      @Recipient bigint,
      @CreationDate datetime,
      @ChangeDate datetime,
      @CreationAuthor bigint,
      @IsParent bit,
      @ParentObjectId bigint,
      @ParentObjectUid uniqueidentifier,
      @ChildCount int,
      @IsRead bit,
      @ReadDate datetime,
      @HasUnreadChild bit,
      @UnreadCount int,
      @Priority int,
      @ChangeDateHash nvarchar(35),
      @MessageAttachments varbinary(max),
      @ObjectRecipients varbinary(max),
      @MessageObjects varbinary(max),
      @Url nvarchar(max),
      @TextHtml nvarchar(max)

    select
        @Id = Id,
        @Subject = Subject,
        @Text = Text,
        @ActionObjectUid = ActionObjectUid,
        @ActionUid = ActionUid,
        @ActionObjectId = ActionObjectId,
        @Recipient = Recipient,
        @CreationDate = CreationDate,
        @ChangeDate = ChangeDate,
        @CreationAuthor = CreationAuthor,
        @IsParent = IsParent,
        @ParentObjectId = ParentObjectId,
        @ParentObjectUid = ParentObjectUid,
        @ChildCount = ChildCount,
        @IsRead = IsRead,
        @ReadDate = ReadDate,
        @HasUnreadChild = HasUnreadChild,
        @UnreadCount = UnreadCount,
        @Priority = Priority,
        @ChangeDateHash = ChangeDateHash,
        @MessageAttachments = MessageAttachments,
        @ObjectRecipients = ObjectRecipients,
        @MessageObjects = MessageObjects,
        @Url = Url,
        @TextHtml = TextHtml
    from Feed with (nolock)
    where
        IsParent = 1
              and Recipient = @p_Recipient
              and ParentObjectId = @p_ParentObjectId
              and ParentObjectUid = @p_ParentObjectUid

    if (@Id is null)
    begin
        select
            @Id = Id,
            @Subject = Subject,
            @Text = Text,
            @ActionObjectUid = ActionObjectUid,
            @ActionUid = ActionUid,
            @ActionObjectId = ActionObjectId,
            @Recipient = Recipient,
            @CreationDate = CreationDate,
            @ChangeDate = ChangeDate,
            @CreationAuthor = CreationAuthor,
            @IsParent = IsParent,
            @ParentObjectId = ParentObjectId,
            @ParentObjectUid = ParentObjectUid,
            @ChildCount = ChildCount,
            @IsRead = IsRead,
            @ReadDate = ReadDate,
            @HasUnreadChild = HasUnreadChild,
            @UnreadCount = UnreadCount,
            @Priority = Priority,
            @ChangeDateHash = ChangeDateHash,
            @MessageAttachments = MessageAttachments,
            @ObjectRecipients = ObjectRecipients,
            @MessageObjects = MessageObjects,
            @Url = Url,
            @TextHtml = TextHtml
        from FeedArchive with (nolock)
        where
              Recipient = @p_Recipient
              and ParentObjectId = @p_ParentObjectId
              and ParentObjectUid = @p_ParentObjectUid
        and IsParent = 1
    end

    select
        @Id Id,
        @Subject Subject,
        @Text Text,
        @ActionObjectUid ActionObjectUid,
        @ActionUid ActionUid,
        @ActionObjectId ActionObjectId,
        @Recipient Recipient,
        @CreationDate CreationDate,
        @ChangeDate ChangeDate,
        @CreationAuthor CreationAuthor,
        @IsParent IsParent,
        @ParentObjectId ParentObjectId,
        @ParentObjectUid ParentObjectUid,
        @ChildCount ChildCount,
        @IsRead IsRead,
        @ReadDate ReadDate,
        @HasUnreadChild HasUnreadChild,
        @UnreadCount UnreadCount,
        @Priority Priority,
        @ChangeDateHash ChangeDateHash,
        @MessageAttachments MessageAttachments,
        @ObjectRecipients ObjectRecipients,
        @MessageObjects MessageObjects,
        @Url Url,
        @TextHtml TextHtml
    where not @Id is null

END


/**************************************************************************************

   Загружает комментарии к сообщению ленты.

**************************************************************************************/
CREATE PROCEDURE FeedCommentsLoad
    @Recipient bigint,
    @ParentObjectUid uniqueidentifier,
    @ParentObjectId bigint,
    @ChangeDateHash nvarchar(16),
    @MaxChildCount bigint
AS
BEGIN

    select *
    from Feed with (NOLOCK)
    where ParentObjectId = @ParentObjectId
      and ParentObjectUid = @ParentObjectUid
      and Recipient = @Recipient
      and IsParent = 1
    union all
    select * from (select top (@MaxChildCount) *
        from Feed with (nolock)
        where ParentObjectId = @ParentObjectId
          and ParentObjectUid = @ParentObjectUid
          and Recipient = @Recipient
          and IsParent = 0
          and ChangeDateHash < isnull(@ChangeDateHash, 'z')
          order by ChangeDateHash desc
    ) fc

END


/**************************************************************************************

   Создаёт заданное количество идентификаторов для таблицы Feed и возвращает первый из них.

**************************************************************************************/
CREATE PROCEDURE FeedGetNewIds
  @Count bigint
AS
BEGIN

    declare @feedId bigint;
    set @feedId = 0;
    exec [G_GenId] 'Feed', @Count, @feedId OUTPUT;
    select @feedId Id;

END
